public void connect() throws java.io.IOException {
    // {
    if (true) {
        java.io.BufferedReader in = this.in;// use locals so NPE-analysis works

        java.io.PrintWriter out = this.out;
        java.lang.String response = "";
        javax.net.SocketFactory socketFactory = new jif.net.JifSocketFactory();
        java.lang.String userString = "user " + this.username;
        java.lang.String pw = null;
        try {
            pw = new java.lang.String(this.password);
        } catch (java.lang.NullPointerException e) {
        }
        // DECLASSIFICATION: need to declassify the password before sending it to the Socket
        // String passString = "pass " + declassify(pw);
        if (this.debug != null) {
            // debug.println("Pass is: " + pw);
            this.debug.println("username is: " + this.username);
            this.debug.println("mailhost is: " + this.mailhost);
        }
        // No need to connect
        if (this.isConnected) {
            return;
        }
        // Handle SSL properly
        // if (isSSL) {
        // socketFactory = SSLSocketFactory[].getDefault();
        // } else {
        // socketFactory = SocketFactory[].getDefault();
        // }
        final java.net.Socket sock = socketFactory.createSocket(this.mailhost, this.mailport);
        this.sock = sock;
        // configure socket io streams
        if (sock != null) {
            in = new java.io.BufferedReader(new java.io.InputStreamReader(sock.getInputStream()));
            out = new java.io.PrintWriter(sock.getOutputStream(), true);
        } else if (this.debug != null) {
            this.debug.println("Socket is null for some reason.");
        }
        smtp.DigestMD5 mmd5 = null;
        try {
            mmd5 = new smtp.DigestMD5();
        } catch (java.security.NoSuchAlgorithmException nsae) {
        } catch (java.security.NoSuchProviderException nspe) {
        }
        final smtp.DigestMD5 md5 = mmd5;
        // log in
        java.lang.String okLine = null;
        if ((in != null) && (out != null)) {
            okLine = in.readLine();// consume welcome banner: e.g. "+OK POP3 server ready <1896.697170952@dbc.mtview.ca.us>"

            if (this.debug != null) {
                this.debug.println("okLine: " + okLine);
            }
            java.lang.String apopChallenge = null;
            if (md5 != null) {
                apopChallenge = md5.authAPOP(okLine);
            }// e.g. 1896.697170952@dbc.mtview.ca.us

            if (this.debug != null) {
                this.debug.println("APOP challenge: " + apopChallenge);
            }
            java.lang.String digest = null;
            if (md5 != null) {
                digest = md5.getAPOPDigest(pw, apopChallenge);
            }
            if (this.debug != null) {
                this.debug.println("APOP digest: " + digest);
            }
            out.println((("APOP " + this.username) + " ") + digest);// "APOP user MD5(<1896.697170952@dbc.mtview.ca.us>password"

            response = in.readLine();// confirm APOP accepted: e.g. "+OK maildrop has 1 message (369 octets)"

        } else if (this.debug != null) {
            this.debug.println("socket I/O is null for some reason");
        }
        /* String okLine = null;
        if (in != null && out != null) {
        okLine = in.readLine();	    // consume welcome banner
        out.println(userString);            // send username
        response = in.readLine();	    // consume "+OK plese send PASS command"
        out.println(passString);            // send password
        response = in.readLine();	    // confirm password accepted
        }
        else if (debug != null) debug.println("socket I/O is null for some reason");
         */
        if (response != null) {
            try {
                if (response.substring(0, 3).compareTo("+OK") != 0) {
                    if (this.debug != null) {
                        this.debug.println("Error: response is: " + response);
                    }
                }
            } catch (java.lang.StringIndexOutOfBoundsException e) {
            } catch (java.lang.NullPointerException e) {
            }
        }
        this.isConnected = true;
        this.in = in;
        this.out = out;
        this.messageCount = pop3.MailReaderCrypto.INVALID_MESG_COUNT;
    }
}

