public static jif.lang.Principal[] findDelegatesChain(jif.lang.Principal p, jif.lang.Principal q) {
    /* System.out.print("findDelegatesChain(");
    if (p == null) System.out.print("null, ");
    else System.out.print(p.toString() + ", ");
    if (q == null) System.out.println("null)");
    else System.out.println(q.toString() + ")");
     */
    // try the dumb things first.
    if (p == q) {
        jif.lang.Principal[] chain = new jif.lang.Principal[1];
        chain[0] = p;
        return chain;
    }
    if ((q == null) || (((p != null) && p.equals(q)) && q.equals(p))) {
        jif.lang.Principal[] chain = new jif.lang.Principal[2];
        chain[0] = p;
        chain[1] = q;
        return chain;
    }
    // try searching upwards from q.
    // System.out.println("q.findChainUpto(p)");
    jif.lang.Principal[] chain = q.findChainUpto(p);
    if (chain != null) {
        return chain;
    }
    // try searching downards from p.
    if (p != null) {
        chain = p.findChainDownto(q);
        if (chain != null) {
            return chain;
        }
    }
    // have failed!
    return null;
}

