public static char[] getPassword(java.lang.String pwdFilename, java.security.Principal pwdP) {
    java.lang.String _returnString = null;// should return the password at level PwdL

    jif.runtime.Runtime runtime = null;
    try {
        runtime = jif.runtime.Runtime.getRuntime();
    } catch (java.lang.SecurityException e) {
    }
    java.io.PrintStream outS = null;
    try {
        outS = runtime.stdout();
    } catch (java.lang.SecurityException ex) {
        /* should do something here */
    } catch (java.lang.NullPointerException e) {
    }
    if (outS != null) {
        outS.println("=========Got runtime from Password=========");
        outS.println("Reading in password from " + pwdFilename);
    }
    java.io.FileInputStream inPassword = null;
    java.io.FileInputStream inIV = null;
    java.io.FileInputStream inKey = null;
    try {
        // upgrading takes place here from PwdL to , made possible by dynamic check
        inPassword = runtime.openFileRead(pwdFilename);
        inIV = runtime.openFileRead(pwdFilename + "_iv");
        inKey = runtime.openFileRead(pwdFilename + "_key");
    } catch (java.io.IOException ignore) {
        if (outS != null) {
            outS.println("****IOException");
        }
    } catch (java.lang.SecurityException ignore) {
        if (outS != null) {
            outS.println("****SecurityException: " + ignore.toString());
        }
    } catch (java.lang.NullPointerException ignore) {
        if (outS != null) {
            outS.println("****NullPointerException");
        }
    }
    // read in key
    byte[] keyBits = null;
    if (inKey != null) {
        try {
            int keylen = inKey.available();
            keyBits = new byte[keylen];
            for (int i = 0; i < keylen; i++) {
                keyBits[i] = ((byte) (inKey.read()));
            }
            inKey.close();
        } catch (java.io.IOException ignore) {
        } catch (java.lang.ArrayIndexOutOfBoundsException impossible) {
        }
    }
    java.security.Key myKey1 = new javax.crypto.spec.SecretKeySpec(keyBits, "DES");
    // read in IV
    byte[] ivBits = null;
    if (inIV != null) {
        try {
            int ivlen = inIV.available();
            ivBits = new byte[ivlen];
            for (int i = 0; i < ivlen; i++) {
                ivBits[i] = ((byte) (inIV.read()));
            }
            inIV.close();
        } catch (java.io.IOException ignore) {
        } catch (java.lang.ArrayIndexOutOfBoundsException impossible) {
        }
    }
    // read in encText
    byte[] pwdBits = null;
    if (inPassword != null) {
        try {
            int pwdlen = inPassword.available();
            pwdBits = new byte[pwdlen];
            for (int i = 0; i < pwdlen; i++) {
                pwdBits[i] = ((byte) (inPassword.read()));
            }
            inPassword.close();
        } catch (java.io.IOException ignore) {
        } catch (java.lang.ArrayIndexOutOfBoundsException impossible) {
        }
    }
    // cipher text is public, because it's encrypted.
    final crypto.Ciphertext ciphertext = new crypto.Ciphertext(pwdBits, ivBits);
    java.lang.String encOutputString = null;
    try {
        encOutputString = new java.lang.String(ciphertext.encText);
    } catch (java.lang.NullPointerException ignore) {
    }
    // decryption
    try {
        _returnString = ((java.lang.String) (crypto.DES.decrypt(myKey1, ciphertext)));// decrypts and upgrades security to PwdL

    } catch (java.security.InvalidKeyException ex) {
        // ignore these for now
    } catch (javax.crypto.IllegalBlockSizeException ex) {
    } catch (javax.crypto.BadPaddingException ex) {
    } catch (javax.crypto.NoSuchPaddingException ex) {
    } catch (java.security.InvalidAlgorithmParameterException ex) {
    } catch (java.security.NoSuchAlgorithmException ex) {
    } catch (java.lang.NullPointerException ex) {
    }
    final java.lang.String returnString = _returnString;
    return returnString == null ? null : returnString.toCharArray();
}

