public static pop3.MimeMailMessage getMimeMailMessage(java.io.BufferedReader in) {
    if (in == null) {
        return null;
    }
    pop3.MimeHeader header = null;
    pop3.MimePart[] bodyParts = new pop3.MimePart[10];
    int numParts = 0;
    header = pop3.MimeHeader.getMimeHeader(in);
    // read in dead text between header and first MimePart
    java.lang.String resp = null;
    try {
        do {
            resp = in.readLine();
        } while (!resp.startsWith(header.getBeginBoundary()) );
    } catch (java.lang.NullPointerException ignore) {
        // thrown by resp.compareTo(...)
    } catch (java.io.IOException ignore) {
    }
    pop3.MimePart part = null;
    try {
        do {
            part = pop3.MimePart.getMimePart(in, header);
            if (numParts >= bodyParts.length) {
                // ran out of space; reallocate 10 more and copy
                pop3.MimePart[] temp = new pop3.MimePart[numParts + 10];
                // save existing body parts
                for (int i = 0; i < numParts; i++) {
                    temp[i] = bodyParts[i];
                }
                bodyParts = new pop3.MimePart[numParts + 10];// reallocate more space

                for (int i = 0; i < numParts; i++) {
                    bodyParts[i] = temp[i];
                }// copy back into bodyParts

            }
            bodyParts[numParts++] = part;
        } while ((part != null) && (!part.isLast()) );
    } catch (java.lang.ArrayIndexOutOfBoundsException ignore) {
        // shouldn't happen, because we check
    } catch (java.lang.ArrayStoreException ignore) {
        // apparently caused by assigning temp[i] = bodyParts[i] and vice versa
    }
    // read out the epilogue until the end, indicated by "."
    try {
        do {
            resp = in.readLine();
        } while (resp.compareTo(".") != 0 );
    } catch (java.lang.NullPointerException ignore) {
        // thrown by resp.compareTo(...)
    } catch (java.io.IOException ignore) {
    }
    return new pop3.MimeMailMessage(header, bodyParts, numParts);
}

