    if ((q == null) || (((p != null) && p.equals(q)) && q.equals(p))) {
        jif.lang.Principal[] chain = new jif.lang.Principal[2];
        chain[0] = p;
        chain[1] = q;
        return chain;
    }
    // try searching upwards from q.
