public byte[] authClient(java.lang.String host, java.lang.String user, java.lang.String passwd, java.lang.String realmInput, java.lang.String serverChallenge, java.io.PrintStream debugout, java.security.Principal debugP) throws java.io.IOException {
    java.io.ByteArrayOutputStream bos = new java.io.ByteArrayOutputStream();
    java.io.OutputStream b64os = new com.sun.mail.util.BASE64EncoderStream(bos, java.lang.Integer.MAX_VALUE);
    java.security.SecureRandom random = new java.security.SecureRandom();
    java.lang.String realm = realmInput;
    final java.lang.StringBuffer result = new java.lang.StringBuffer();
    this.uri = "smtp/" + host;
    java.lang.String nc = "00000001";
    java.lang.String qop = "auth";
    byte[] bytes = new byte[32];// arbitrary size ...

    int resp;
    if (debugout != null) {
        debugout.println("DEBUG DIGEST-MD5: Begin authentication ...");
    }
    // Code based on http://www.ietf.org/rfc/rfc2831.txt
    final java.util.Map map = this.tokenize(serverChallenge);
    if (map == null) {
        if (debugout != null) {
            debugout.println("Couldn't tokenize map!");
        }
        return null;
    } else {
        final java.lang.Object r = map.get("realm");
        final java.lang.Object n = map.get("nonce");
        final java.lang.Object q = map.get("qop");
        final java.lang.Object c = map.get("cipher");
        if (debugout != null) {
            debugout.println("realm --> " + (r != null ? r.toString() : "**"));
            debugout.println("nonce --> " + (n != null ? n.toString() : "**"));
            debugout.println("qop --> " + (q != null ? q.toString() : "**"));
            debugout.println("cipher --> " + (c != null ? c.toString() : "**"));
        }
    }
    if (realm == null) {
        final java.lang.Object jtext = map.get("realm");
        final java.lang.String text = (jtext != null) ? jtext.toString() : null;
        final java.util.StringTokenizer stok = new java.util.StringTokenizer(text, ",");
        try {
            realm = ((text != null) && (stok != null)) ? stok.nextToken() : host;
        } catch (java.util.NoSuchElementException ignore) {
            realm = host;
        }
    }
    // server challenge random value
    final java.lang.Object jnonce = map.get("nonce");
    final java.lang.String nonce = (jnonce != null) ? jnonce.toString() : null;
    random.nextBytes(bytes);
    b64os.write(bytes);
    b64os.flush();
    // client challenge random value
    java.lang.String cnonce = bos.toString();
    bos.reset();
    if (debugout != null) {
        debugout.println("My nonce is: " + cnonce);
    }
    // DIGEST-MD5 computation, common portion (order critical)
    if (this.md5 == null) {
        return null;
    }
    final java.lang.String input1 = (((user + ":") + realm) + ":") + passwd;
    final java.lang.String input2 = ((":" + nonce) + ":") + cnonce;
    // DECLASSIFICATION!!
    final crypto.MD5Closure md5clo = new crypto.MD5Closure(this.md5, input1);
    byte[] input1_declass = null;
    final java.security.Principal p = null;
    try {
        input1_declass = ((byte[]) (jif.lang.PrincipalUtil.authorize(p, null, md5clo).invoke()));
    } catch (java.lang.NullPointerException e) {
        if ((debugout != null) && (p != null)) {
            debugout.println("Authorization failed for " + p.getName());
        }
    }// authorization failed

    this.md5.update(input1_declass);
    this.md5.update(input2 != null ? input2.getBytes() : null);
    this.clientResponse = ((((((((smtp.DigestMD5.toHex(this.md5.digest()) + ":") + nonce) + ":") + nc) + ":") + cnonce) + ":") + qop) + ":";
    if (debugout != null) {
        debugout.println("Client RESPONSE to be: " + this.clientResponse);
    }
    // DIGEST-MD5 computation, client response (order critical)
    final java.lang.String input3 = "AUTHENTICATE:" + this.uri;
    this.md5.update(input3 != null ? input3.getBytes() : null);
    final java.lang.String input4 = this.clientResponse + smtp.DigestMD5.toHex(this.md5.digest());
    this.md5.update(input4 != null ? input4.getBytes() : null);
    // build response text (order not critical)
    result.append(("username=\"" + user) + "\"");
    result.append((",realm=\"" + realm) + "\"");
    result.append(",qop=" + qop);
    result.append(",nc=" + nc);
    result.append((",nonce=\"" + nonce) + "\"");
    result.append((",cnonce=\"" + cnonce) + "\"");
    result.append((",digest-uri=\"" + this.uri) + "\"");
    result.append(",response=" + smtp.DigestMD5.toHex(this.md5.digest()));
    java.lang.String resultStr = (result != null) ? result.toString() : null;
    if (debugout != null) {
        debugout.println("DEBUG DIGEST-MD5: Response => " + resultStr);
    }
    b64os.write(resultStr != null ? resultStr.getBytes() : null);
    b64os.flush();
    return bos.toByteArray();
}

