public static boolean actsFor(jif.lang.Principal p, jif.lang.Principal q) {
    // System.out.println("PrincipalUtil: testing if " + (p!= null?p.name():"null") + " actsfor " + (q!=null?q.name():"null"));
    // anyone can act for the "null" principal
    if (q == null) {
        return true;
    }
    // if the two principals are ==-equal, or if they
    // both agree that they are equal to each other, then
    // we return true (since the acts-for relation is
    // reflexive).
    if (p == q) {
        return true;
    }
    if ((q.equals(p) && (p != null)) && p.equals(q)) {
        return true;
    }
    // try a simple test first
    if (q.delegatesTo(p)) {
        return true;
    }
    // try the cache
    jif.lang.PrincipalUtil.PrincipalPair pp = new jif.lang.PrincipalUtil.PrincipalPair(p, q);
    jif.lang.Principal[] chain = ((jif.lang.Principal[]) (jif.lang.PrincipalUtil.chainCache.get(pp)));
    if (chain != null) {
        if (jif.lang.PrincipalUtil.verifyChain(chain, p, q)) {
            return true;
        }
        // chain is no longer valid
        jif.lang.PrincipalUtil.chainCache.remove(pp);
    }
    // try searching
    chain = jif.lang.PrincipalUtil.findDelegatesChain(p, q);
    if ((chain != null) && jif.lang.PrincipalUtil.verifyChain(chain, p, q)) {
        // cache the chain to avoid searching later.
        jif.lang.PrincipalUtil.chainCache.put(pp, chain);
        return true;
    }
    // can't do anything more!
    return false;
}

