public static pop3.MimePart makeBase64Attachment(java.lang.String name, byte[] data, boolean isLast, pop3.MimeHeader mimeHeader) {
    if (data == null) {
        return null;
    }
    // need to upgrade data so that all the bytes are actually at level , not just bound above by it
    int len = data.length;
    byte[] temp = new byte[len];
    try {
        for (int i = 0; i < temp.length; i++) {
            temp[i] = data[i];
        }
    } catch (java.lang.ArrayIndexOutOfBoundsException ignore) {
        return null;
    } catch (java.lang.NullPointerException ignore) {
        return null;
    }
    final pop3.MimePartHeader mph = new pop3.MimePartHeader("base64", new pop3.ContentType("text", "plain", ("\"" + name) + "\"", null, null), new pop3.ContentDisposition("attachment", name), mimeHeader);
    final pop3.MimePartBody mpb64 = new pop3.MimePartBase64(isLast, temp);
    return new pop3.MimePart(mph, mpb64);
}

