public java.lang.String sendCmd(byte[] cmd, java.lang.String resp) throws java.io.IOException {
    java.io.BufferedReader in = this.in;// use locals so NPE-analysis works

    java.io.BufferedOutputStream out = this.out;
    // send command to socket
    if (out != null) {
        try {
            java.lang.String cmdStr = new java.lang.String(cmd);
            if ((this.debug != null) && (cmd != null)) {
                this.debug.println(cmdStr);
            }
        } catch (java.lang.NullPointerException impossible) {
        }// from "new String(cmd)"

        out.write(cmd);
        out.write(smtp.MailSenderCrypto.CRLF);
        out.flush();
    }
    // read response
    java.lang.String response = null;
    if (in != null) {
        // TODO: at some point, we'll want to parse this
        do {
            response = in.readLine();
            if (this.debug != null) {
                this.debug.println(response);
            }
        } while (this.isNotLastLine(response) );
    }
    // check response against expected response
    if (response != null) {
        try {
            if (response.substring(0, 3).compareTo(resp) != 0) {
                if (this.debug != null) {
                    this.debug.println("Error: response is: " + response);
                }
            }
        } catch (java.lang.StringIndexOutOfBoundsException e) {
        } catch (java.lang.NullPointerException e) {
        }
    } else if (this.debug != null) {
        this.debug.println("response = NULL");
    }
    return response;
}

