public static boolean verifyChain(jif.lang.Principal[] chain, jif.lang.Principal p, jif.lang.Principal q) {
    if ((chain == null) || (chain.length == 0)) {
        return false;
    }
    if ((chain[0] != p) || (chain[chain.length - 1] != q)) {
        return false;
    }
    // now go through the chain and check it
    for (int i = 0; i < (chain.length - 1); i++) {
        // either i+1 has to be null, or i+1 has to delegate to i
        if ((chain[i + 1] != null) && (!chain[i + 1].delegatesTo(chain[i]))) {
            return false;
        }
    }
    return true;
}

