public static java.security.PrivateKey getPrivateKey(java.io.InputStream in) {
    // read keys from file
    final java.io.ByteArrayOutputStream privKeyBaos = new java.io.ByteArrayOutputStream();
    int curByte = 0;
    java.security.spec.PKCS8EncodedKeySpec privKeySpec = null;
    if ((privKeyBaos != null) && (in != null)) {
        try {
            while ((curByte = in.read()) != (-1)) {
                privKeyBaos.write(curByte);
            } 
        } catch (java.io.IOException e) {
        }
        privKeySpec = new java.security.spec.PKCS8EncodedKeySpec(privKeyBaos.toByteArray());
        try {
            privKeyBaos.close();
