private java.util.Map tokenize(java.lang.String serverResponse) throws java.io.IOException {
    java.util.Map map = new java.util.HashMap();
    final byte[] bytes = (serverResponse != null) ? serverResponse.getBytes() : null;
    if ((bytes == null) || (map == null)) {
        return null;
    }
    java.lang.String key = null;
    int ttype;
    java.io.StreamTokenizer tokens = new java.io.StreamTokenizer(new java.io.InputStreamReader(new com.sun.mail.util.BASE64DecoderStream(new java.io.ByteArrayInputStream(bytes, 4, bytes.length - 4))));
    tokens.ordinaryChars('0', '9');// reset digits

    tokens.wordChars('0', '9');// digits may start words

    while ((ttype = tokens.nextToken()) != java.io.StreamTokenizer.TT_EOF) {
        switch (ttype) {
            case java.io.StreamTokenizer.TT_WORD :
                if (key == null) {
                    key = tokens.sval;
                    break;
                }
                // fall-thru
            case '"' :
                // if (debugout != null)
                // debugout.println("DEBUG DIGEST-MD5: Received => "
                // + key + "='" + tokens.sval + "'");
                if (map.containsKey(key)) {
                    // concatenate multiple values
                    try {
                        java.lang.Object valObj = ((java.lang.Object) (map.get(key)));
                        java.lang.String val = new java.lang.String(valObj != null ? (valObj.toString() + ",") + tokens.sval : null);
                        map.put(key, val);
                    } catch (java.lang.ClassCastException impossible) {
                    }
                } else {
                    map.put(key, new java.lang.String(tokens.sval));
                }
                key = null;
                break;
        }
    } 
    return map;
}

