private static java.lang.String toHex(byte[] bytes) {
    try {
        char[] result = new char[bytes.length * 2];
        for (int index = 0, i = 0; index < bytes.length; index++) {
            int temp = bytes[index] & 0xff;
            result[i++] = smtp.DigestMD5.digits[temp >> 4];
            result[i++] = smtp.DigestMD5.digits[temp & 0xf];
        }
        return new java.lang.String(result);
