}

public static java.lang.Object[] arrayDeepClone(java.lang.Object[] a) {
    if (a == null) {
        return null;
    }
    java.lang.Object[] c = a.clone();
    for (int i = 0; i < a.length; i++) {
        java.lang.Object o = a[i];
        if ((o != null) && o.getClass().isArray()) {
            if (o.getClass().getComponentType().isPrimitive()) {
                // o is of type e.g., int[]. Need to clone it.
                int length = java.lang.reflect.Array.getLength(o);
                o = java.lang.reflect.Array.newInstance(o.getClass().getComponentType(), length);
                java.lang.System.arraycopy(a[i], 0, o, 0, length);
            } else {
                // o i of type C[]
                o = jif.runtime.Runtime.arrayDeepClone(((java.lang.Object[]) (o)));
            }
        }
        c[i] = o;
    }
    return c;
}

public java.lang.String sendCmd(java.lang.String cmd, java.lang.String resp) throws java.io.IOException {
    java.io.BufferedReader in = this.in;// use locals so NPE-analysis works

    java.io.BufferedOutputStream out = this.out;
    // send command to socket
    if ((out != null) && (cmd != null)) {
        if (this.debug != null) {
            this.debug.println(cmd);
        }
        out.write(cmd.getBytes());
        out.write(smtp.MailSenderCrypto.CRLF);
        out.flush();
    }
    // read response
    java.lang.String response = null;
    if (in != null) {
        // TODO: at some point, we'll want to parse this
        do {
            response = in.readLine();
            if (this.debug != null) {
                this.debug.println(response);
            }
        } while (this.isNotLastLine(response) );
    }
    // check response against expected response
    if (response != null) {
        try {
            if (response.substring(0, 3).compareTo(resp) != 0) {
                if (this.debug != null) {
                    this.debug.println((("Error: response is: " + response) + ", but expected ") + resp);
                }
            }
        } catch (java.lang.StringIndexOutOfBoundsException e) {
        } catch (java.lang.NullPointerException e) {
        }
    } else if (this.debug != null) {
        this.debug.println("response = NULL");
    }
    return response;
}

