public static pop3.MimeHeader getMimeHeader(java.io.BufferedReader in) {
    if (in == null) {
        return null;
    }
    java.lang.String toAddress = null;
    java.lang.String fromAddress = null;
    java.lang.String sendDate = null;
    java.lang.String subject = null;
    java.lang.String mailLblStr = null;
    java.lang.String crypto = null;
    pop3.ContentType contentType = null;
    java.lang.String boundary = null;
    java.lang.String mimeVersion = null;
    java.lang.String response = null;
    boolean header = true;
    boolean first = true;
    while (header) {
        try {
            if (first) {
                do {
                    response = in.readLine();
                } while (!response.startsWith("Return-Path:") );
                first = false;
            } else {
                response = in.readLine();
            }
        } catch (java.io.IOException e) {
        } catch (java.lang.NullPointerException ignore) {
        }
        try {
            if (response == null) {
                header = false;
            } else if (response.compareTo("") == 0) {
                header = false;
            } else if (response.compareTo(".") == 0) {
                header = false;
            } else if (response.startsWith("To: ")) {
                toAddress = response.substring("To: ".length());
            } else if (response.startsWith("From: ")) {
                fromAddress = response.substring("From: ".length());
            } else if (response.startsWith("Subject: ")) {
                subject = response.substring("Subject: ".length());
            } else if (response.startsWith("Date: ")) {
                sendDate = response.substring("Date: ".length());
            } else if (response.startsWith("X-Jif-Label: ")) {
                mailLblStr = response.substring("X-Jif-Label: ".length());
            } else if (response.startsWith("X-Crypto:")) {
                crypto = response.substring("X-Crypto: ".length());
            } else if (response.startsWith("Content-Type: ")) {
                contentType = pop3.ContentType.getContentType(response, in);
            } else if (response.startsWith("Mime-Version: ")) {
                mimeVersion = response.substring("Mime-Version: ".length());
            }
        } catch (java.lang.NullPointerException ignore) {
            // response shouldn't be null
        } catch (java.lang.StringIndexOutOfBoundsException ignore) {
        }// shouldn't happen

    } 
    return new pop3.MimeHeader(toAddress, fromAddress, sendDate, subject, mailLblStr, crypto, contentType, mimeVersion);
}

