public pop3.MimeMailMessage toMimeMailMessage(java.io.PrintStream debug, java.security.Principal user) {
    if (debug != null) {
        debug.println("ENTERING toMimeMailMessage...");
    }
    pop3.MimeMailMessage mmm = null;
    // need to get the principal(s) out of rcptLbl
    if (true) {
        boolean success = true;// presume it will work, but, if not, set flag

        java.lang.String disclaimerBody = "";
        smtp.EmailDisclaimerClosure edc = new smtp.EmailDisclaimerClosure(this.getBody());
        try {
            disclaimerBody = ((java.lang.String) (jif.lang.PrincipalUtil.authorize(this.rcptP, null, edc).invoke()));
        } catch (java.lang.ClassCastException ignore) {
        } catch (java.lang.NullPointerException e) {
            success = false;
        }// failed to authorize

        if (success) {
            final pop3.MimePart[] parts = new pop3.MimePart[1];
            try {
                parts[0] = pop3.MimePart.make7bitPart(disclaimerBody, true, this.header);
                mmm = new pop3.MimeMailMessage(this.header, parts, 1);
            } catch (java.lang.NullPointerException ignore) {
            } catch (java.lang.ArrayIndexOutOfBoundsException ignore) {
                // shouldn't happen
            } catch (java.lang.ArrayStoreException ignore) {
            }// not sure what this is

        } else {
            if (debug != null) {
                debug.println("Trying encryption.");
            }
            // common for all encryption types
            java.lang.String crypto = "none";// presume no encryption

            java.security.Key key = null;
            Ciphertext encBody = null;
            // upgrade and copy the body so that it can be sent to DESClosure
            final java.lang.String bodyStr = this.getBody();// upgrade the label on the String

            final byte[] bodyBytes = (bodyStr == null) ? null : bodyStr.getBytes();
            // ---try AES---
            success = true;
            crypto = "AES";
            try {
                key = AES.getNewKey();
            } catch (java.security.NoSuchAlgorithmException impossible) {
            } catch (java.lang.NullPointerException impossible) {
            }
            if (debug != null) {
                debug.println("Trying AES...");
            }
            AESClosure ac = new AESClosure(key, bodyBytes);
            try {
                encBody = ((Ciphertext) (jif.lang.PrincipalUtil.authorize(this.rcptP, null, ac).invoke()));
            } catch (java.lang.ClassCastException ignore) {
            } catch (java.lang.NullPointerException ignore) {
                success = false;
            }// means we didn't get authorization

            if (!success) {
                // ---try DES---
                success = true;
                crypto = "DES";
                try {
                    key = DES.getNewKey();
                } catch (java.security.NoSuchAlgorithmException impossible) {
                } catch (java.lang.NullPointerException impossible) {
                }
                if (debug != null) {
                    debug.println("Trying DES...");
                }
                DESClosure dc = new DESClosure(key, bodyBytes);
                try {
                    encBody = ((Ciphertext) (jif.lang.PrincipalUtil.authorize(this.rcptP, null, dc).invoke()));
                } catch (java.lang.ClassCastException ignore) {
                } catch (java.lang.NullPointerException ignore) {
                    success = false;
                }// means we didn't get authorization

            }
            if (!success) {
                crypto = "failed";
                final pop3.MimeHeader cryptoHeader = (this.header != null) ? this.header.addCrypto(crypto) : null;// add whatever crypto we used.

                final pop3.MimePart[] parts = new pop3.MimePart[1];
                try {
                    parts[0] = pop3.MimePart.make7bitPart("<CANNOT DISCLOSE BODY>", true, cryptoHeader);
                } catch (java.lang.NullPointerException ignore) {
                    // caused by key.getEncoded or encBody.*
                } catch (java.lang.ArrayIndexOutOfBoundsException ignore) {
                    // shouldn't happen
                } catch (java.lang.ArrayStoreException ignore) {
                }// not sure what this is

                mmm = new pop3.MimeMailMessage(cryptoHeader, parts, 3);
            } else {
                // able to encrypt in some way so package up the key and IV with the ciphertext in the MimeBody
                byte[] keyBits1 = null;
                try {
                    keyBits1 = key.getEncoded();
                } catch (java.lang.NullPointerException ignore) {
                }
                // encrypt and add key to MimeMailMessage
                // we only need to declassify because we didn't encrypt yet -- should be removed eventually -- DONE
                // DeclassKeyClosure dkc = new DeclassKeyClosure(keyBits1);
                java.security.PublicKey rcptKey = null;
                if (this.rcptP instanceof policy.KeyPrincipal) {
                    rcptKey = ((policy.KeyPrincipal) (this.rcptP)).getPublicKey();
                }
                RSAClosure rsaClo = new RSAClosure(rcptKey, keyBits1);
                byte[] keyBits = null;
                try {
                    keyBits = ((Ciphertext) (jif.lang.PrincipalUtil.authorize(this.rcptP, null, rsaClo).invoke())).encText;
                } catch (java.lang.NullPointerException ignore) {
                    // would mean the authorization failed
                } catch (java.lang.ClassCastException ignore) {
                }
                // create the Message
                final pop3.MimeHeader cryptoHeader = (this.header != null) ? this.header.addCrypto(crypto) : null;// add whatever crypto we used.

                final pop3.MimePart[] parts = new pop3.MimePart[3];
                try {
                    parts[0] = pop3.MimePart.makeBase64Attachment("key", keyBits, false, cryptoHeader);
                    // if (parts != null && parts[0] != null && outS != null) outS.println("Made the first part -- KEY");
                    // add IV to MimeMailMessage
                    parts[1] = pop3.MimePart.makeBase64Attachment("iv", encBody.iv, false, cryptoHeader);
                    // if (parts != null && parts[1] != null && outS != null) outS.println("Made the second part -- IV");
                    // add encrypted body to MimeMailMessage
                    parts[2] = pop3.MimePart.makeBase64Attachment("body", encBody.encText, true, cryptoHeader);
                    mmm = new pop3.MimeMailMessage(cryptoHeader, parts, 3);
                } catch (java.lang.NullPointerException ignore) {
                    // caused by key.getEncoded or encBody.*
                } catch (java.lang.ArrayIndexOutOfBoundsException ignore) {
                    // shouldn't happen
                } catch (java.lang.ArrayStoreException ignore) {
                }// not sure what this is

            }
        }
    }
    return mmm;
}

