    if (in == null) {
        return null;
    }
    java.lang.String body = "";
    boolean isLast = false;
    java.lang.String response = null;
    boolean inBody = true;
    while (inBody) {
        try {
            response = in.readLine();
        } catch (java.io.IOException e) {
        }
        try {
            if (response == null) {
                inBody = false;
            } else if (response == "") {
            } else if (response.startsWith("--" + boundary)) {
                inBody = false;// end body

                if (response.startsWith(("--" + boundary) + "--")) {
                    isLast = true;
                }// last body

            } else {
                body += response;
            }
        } catch (java.lang.NullPointerException ignore) {
        }// response shouldn't be null

    } 
    // convert string to byte array via b64 encoding
    final java.lang.String allBits = body;
    // if (allBits != null)
    // return new MimePartBase64(isLast,BASE64DecoderStream.decode(allBits.getBytes()));
    // else return null;
    if (allBits != null) {
        final java.io.ByteArrayInputStream bais = new java.io.ByteArrayInputStream(allBits.getBytes());
        final com.sun.mail.util.BASE64DecoderStream ba64is = new com.sun.mail.util.BASE64DecoderStream(bais);
        try {
            if (ba64is != null) {
                final byte[] bodyBytes = new byte[ba64is.available()];// this actually over-allocates since available() counts CRLF's

                int len = 0;
                int val;
                try {
                    while ((val = ba64is.read()) != (-1)) {
                        bodyBytes[len++] = ((byte) (val));
                    } 
                    // ba64is.read(bodyBytes,0,ba64is.available());
                    final byte[] outputBytes = new byte[len];// allocate the number of bytes which were actually read in

                    // copy the "real" values
                    for (int i = 0; i < len; i++) {
                        outputBytes[i] = bodyBytes[i];
                    }
                    return new pop3.MimePartBase64(isLast, outputBytes);
                } catch (java.lang.ArrayIndexOutOfBoundsException e) {
                    return null;
                }
            } else {
                return null;
            }
        } catch (java.io.IOException ignore) {
            return null;
        }// due to ba64is.read(...) and ba64is.available(...)

    } else {
        return null;
    }
}

